import { motion } from 'framer-motion';
import { FiUpload, FiArrowRight, FiPlay } from 'react-icons/fi';
import { Player } from '@lottiefiles/react-lottie-player';

const Hero = () => {
  return (
    <section className="relative overflow-hidden bg-gradient-to-br from-gray-900 to-purple-900 py-24 md:py-32">
      {/* Animated particles background */}
      <div className="absolute inset-0 opacity-20">
        {[...Array(30)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute rounded-full bg-purple-500"
            style={{
              width: `${Math.random() * 8 + 2}px`,
              height: `${Math.random() * 8 + 2}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              x: [0, (Math.random() - 0.5) * 50],
              y: [0, (Math.random() - 0.5) * 50],
              opacity: [0.1, 0.8, 0.1],
            }}
            transition={{
              duration: 10 + Math.random() * 20,
              repeat: Infinity,
            }}
          />
        ))}
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 grid lg:grid-cols-2 gap-12 items-center">
        {/* Text Content */}
        <div className="text-center lg:text-left">
          {/* Headline */}
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <span className="block">Detect Deepfakes Instantly</span>
            <span className="bg-gradient-to-r from-purple-400 to-cyan-300 bg-clip-text text-transparent">
              with AI-Powered Accuracy
            </span>
          </motion.h1>

          {/* Subheadline */}
          <motion.p
            className="text-lg md:text-xl text-gray-300 mb-10 max-w-lg mx-auto lg:mx-0"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.6 }}
          >
            Upload an image and let our system tell you whether it's real or fake — in seconds.
          </motion.p>

          {/* CTA Buttons */}
          <motion.div 
            className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            <motion.a
              href="#upload-section"
              className="flex items-center justify-center gap-2 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-6 py-3 rounded-lg font-medium shadow-lg hover:shadow-xl transition-all group"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.98 }}
            >
              <FiUpload className="group-hover:animate-bounce" />
              Try It Now
              <FiArrowRight className="ml-1 group-hover:translate-x-1 transition-transform" />
            </motion.a>

            <motion.a
              href="#how-it-works"
              className="flex items-center justify-center gap-2 text-white px-6 py-3 rounded-lg font-medium border border-white/20 hover:bg-white/10 transition-colors group"
              whileHover={{ y: -2 }}
            >
              <FiPlay className="text-purple-400 group-hover:text-purple-300" />
              Learn How It Works
            </motion.a>
          </motion.div>
        </div>

        {/* AI Detection Visualization */}
<div className="relative h-80 md:h-96 lg:h-full">
  <Player
    autoplay
    loop
    src="https://assets5.lottiefiles.com/packages/lf20_uzk96t3q.json" // AI brain scan animation
    className="w-full h-full"
    speed={1}
  />
  <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
    {/* Glow effect */}
    <div className="absolute h-64 w-64 rounded-full bg-gradient-to-r from-purple-500/20 to-blue-500/10 blur-xl" />
    
    {/* Floating detection indicators */}
    <motion.div
      className="absolute top-1/4 left-1/4 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-md"
      animate={{
        scale: [1, 1.1, 1],
        opacity: [0.8, 1, 0.8]
      }}
      transition={{
        duration: 2,
        repeat: Infinity
      }}
    >
      FAKE
    </motion.div>
    
    <motion.div
      className="absolute bottom-1/4 right-1/4 bg-green-500 text-white text-xs font-bold px-2 py-1 rounded-md"
      animate={{
        scale: [1, 1.1, 1],
        opacity: [0.8, 1, 0.8]
      }}
      transition={{
        duration: 2,
        repeat: Infinity,
        delay: 1
      }}
    >
      REAL
    </motion.div>
  </div>
</div>
      </div>
    </section>
  );
};

export default Hero;
